1.3 Custom Tooltip Style


Code
tooltip_css &lt;- "
  background-color: white;
  color: black;
  font-weight: bold;
  padding: 6px;
  border-radius: 4px;
  border: 1px solid #333333;
"

p &lt;- ggplot(exam_data, aes(x = MATHS)) +
  geom_dotplot_interactive(
    aes(tooltip = tooltip_text),
    stackgroups = TRUE,
    binwidth = 1,
    method = "histodot"
  ) +
  scale_y_continuous(NULL, breaks = NULL) +
  labs(
    title = "Custom Tooltip Style",
    x = "Maths Score"
  )

girafe(
  ggobj = p,
  width_svg = 8,
  height_svg = 4,
  options = list(
    opts_tooltip(css = tooltip_css)
  )
)
